/// Validate that the header level is within valid range (1-6).
///
/// # Returns
///
/// `true` if level is 1-6, `false` otherwise.
///
/// # Examples
///
/// ```
/// # use html_to_markdown_rs::metadata::HeaderMetadata;
/// let valid = HeaderMetadata {
///     level: 3,
///     text: "Title".to_string(),
///     id: None,
///     depth: 2,
///     html_offset: 100,
/// };
/// assert!(valid.is_valid());
///
/// let invalid = HeaderMetadata {
///     level: 7,  // Invalid
///     text: "Title".to_string(),
///     id: None,
///     depth: 2,
///     html_offset: 100,
/// };
/// assert!(!invalid.is_valid());
/// ```
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn htm_header_metadata_is_valid(
    this: *const html_to_markdown_rs::metadata::HeaderMetadata,
) -> i32 {
    clear_last_error();
    if this.is_null() {
        set_last_error(1, "Null pointer passed for self");
        return 0;
    }
    // SAFETY: null check above guarantees this is a valid pointer.
    let obj = unsafe { &*this };
    let result = obj.is_valid();
    if result {
        1
    } else {
        0
    }
}

